/**
 * Side-effect import entry point.
 *
 * Usage:
 *   import "@munesoft/envx/config";
 *
 * This immediately begins loading and validating environment variables.
 * Top-level await is used so that by the time the next import resolves,
 * process.env is already populated and validated.
 */

import { load } from "./loader.js";

// Top-level await: blocks module graph until env is loaded
await load();
